        while True:
            score = self.request_value_between("Score:", 1, 5)
            while True:
                response = self.request_value("Response:")

                answer = response.strip()
                if answer == "":
                    return None

                if not answer.startswith('{') or not answer.endswith('}'):
                    continue

                try:
                    json_obj = json.loads(answer)
                except json.JSONDecodeError as ex:
                    print(ex.msg)
                    continue

                if "score" not in json_obj or "response" not in json_obj:
                    return None

                break

            return {"score": score, "response": response}


